+        let mut state = TooltipState::new();
+        let target = Rect::new(10, 10, 5, 2);
+
+        state.start_hover(target, 0);
+        state.update(600, 500);
+        assert!(state.is_visible());
+
+        state.hide();
+        assert!(!state.is_visible());
+        assert!(state.target().is_none());
